-- Update email templates for ProdeCaballito to responsive HTML design
-- Navy #001A4B + white background + orange #F47C00 CTA buttons
-- Overrides previous migration 20260525190000_migrate_email_templates_html

DO $$
DECLARE
  v_tenant_id text;
BEGIN
  SELECT id INTO v_tenant_id FROM tenants WHERE slug = 'prodecaballito';
  IF v_tenant_id IS NULL THEN RETURN; END IF;

  -- email_verification_code
  UPDATE templates SET
    subject = $subj_1$🎯 Código de Verificación - PRODE Caballito$subj_1$,
    body = $body_1$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr><tr><td style="padding:32px 32px 16px;text-align:center;"><p style="margin:0;font-size:16px;color:#475569;">Hola, <strong style="color:#001A4B;">{{user.nombre}}</strong></p><p style="margin:10px 0 0;font-size:16px;color:#1E293B;">Tu código de verificación es:</p></td></tr><tr><td style="padding:16px 32px;text-align:center;"><div style="display:inline-block;background:#F1F5F9;border:2px dashed #CBD5E1;border-radius:12px;padding:24px 40px;"><span style="font-family:'Courier New',Courier,monospace;font-size:42px;font-weight:700;color:#001A4B;letter-spacing:8px;">{{business_context.code}}</span></div></td></tr><tr><td style="padding:16px 32px 32px;text-align:center;"><p style="margin:0;font-size:14px;color:#64748B;">Este código <strong>expira en 15 minutos</strong>.</p><p style="margin:12px 0 0;font-size:13px;color:#94A3B8;">Si no solicitaste esto, ignorá este correo.</p></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_1$,
    "updatedAt" = now()
  WHERE name = 'email_verification_code' AND "tenantId" = v_tenant_id;

  -- email_welcome
  UPDATE templates SET
    subject = $subj_2$🔥 ¡{{user.nombre}}, el Mundial 2026 arranca — ya sos parte del PRODE!$subj_2$,
    body = $body_2$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr><tr><td style="background:#001A4B;padding:0 32px 32px;text-align:center;"><p style="margin:0;font-size:38px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#F47C00;letter-spacing:-1px;line-height:1.1;">ESTO YA EMPEZÓ</p><p style="margin:8px 0 0;font-size:18px;color:#93C5FD;font-weight:700;">¿VAS A JUGAR O MIRAR?</p></td></tr><tr><td style="padding:28px 32px 8px;"><p style="margin:0;font-size:16px;color:#1E293B;">Hola <strong style="color:#001A4B;">{{user.nombre}}</strong>, YA ESTÁS ADENTRO del PRODE Caballito.</p><p style="margin:10px 0 0;font-size:15px;color:#475569;line-height:1.6;">Cargá tus pronósticos antes de que empiece la acción.</p></td></tr><tr><td style="padding:16px 32px 8px;"><table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #E2E8F0;border-radius:8px;overflow:hidden;"><tr><td style="background:#F1F5F9;padding:10px 16px;"><p style="margin:0;font-size:12px;font-weight:700;color:#64748B;text-transform:uppercase;letter-spacing:0.5px;">CÓMO JUGAR EN 3 PASOS</p></td></tr><tr><td style="padding:12px 16px;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:14px;color:#1E293B;"><strong style="color:#F47C00;">1.</strong> Entrá a /apuestas → seleccioná el torneo</p></td></tr><tr><td style="padding:12px 16px;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:14px;color:#1E293B;"><strong style="color:#F47C00;">2.</strong> Ingresá el marcador para cada partido</p></td></tr><tr><td style="padding:12px 16px;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:14px;color:#1E293B;"><strong style="color:#F47C00;">3.</strong> ¡Guardá y listo! (se guarda automático)</p></td></tr></table></td></tr><tr><td style="padding:16px 32px 8px;"><table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #E2E8F0;border-radius:8px;overflow:hidden;"><tr><td colspan="2" style="background:#001A4B;padding:10px 16px;text-align:center;"><p style="margin:0;font-size:12px;font-weight:700;color:#ffffff;text-transform:uppercase;letter-spacing:0.5px;">SISTEMA DE PUNTOS</p></td></tr><tr><td style="padding:10px 16px;border-top:1px solid #E2E8F0;font-size:14px;color:#1E293B;">Marcador exacto (ej: 2-1 = 2-1)</td><td style="padding:10px 16px;border-top:1px solid #E2E8F0;text-align:right;font-size:16px;font-weight:900;color:#F47C00;">4 pts</td></tr><tr><td style="padding:10px 16px;border-top:1px solid #E2E8F0;font-size:14px;color:#1E293B;">Resultado correcto (local gana)</td><td style="padding:10px 16px;border-top:1px solid #E2E8F0;text-align:right;font-size:16px;font-weight:900;color:#001A4B;">3 pts</td></tr><tr><td style="padding:10px 16px;border-top:1px solid #E2E8F0;font-size:14px;color:#1E293B;">No acertaste nada</td><td style="padding:10px 16px;border-top:1px solid #E2E8F0;text-align:right;font-size:16px;font-weight:700;color:#94A3B8;">0 pts</td></tr></table></td></tr><tr><td style="padding:16px 32px 8px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#FFFBEB;border:1px solid #FCD34D;border-radius:8px;padding:12px 16px;"><p style="margin:0;font-size:14px;color:#92400E;">⏰ <strong>Las apuestas cierran 5 minutos antes del primer partido.</strong></p></td></tr></table></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="https://prodecaballito.com/apuestas" style="display:inline-block;background:#F47C00;color:#ffffff;font-family:'Arial Black',Arial,sans-serif;font-weight:900;font-size:16px;padding:16px 36px;border-radius:50px;text-decoration:none;">⚽ EMPEZAR A JUGAR AHORA →</a></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_2$,
    "updatedAt" = now()
  WHERE name = 'email_welcome' AND "tenantId" = v_tenant_id;

  -- email_result_individual
  UPDATE templates SET
    subject = $subj_3$🎯 Resultado: {{business_context.home_team}} {{business_context.resultado_local}}-{{business_context.resultado_visitante}} {{business_context.away_team}} — sumaste {{business_context.puntos_obtenidos}} pts$subj_3$,
    body = $body_3$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr><tr><td style="background:#001A4B;padding:28px 32px;text-align:center;"><p style="margin:0;font-size:30px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">{{business_context.home_team}}</p><p style="margin:8px 0;font-size:44px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#F47C00;letter-spacing:2px;">{{business_context.resultado_local}} - {{business_context.resultado_visitante}}</p><p style="margin:0;font-size:30px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">{{business_context.away_team}}</p></td></tr><tr><td style="padding:24px 32px 8px;"><p style="margin:0;font-size:15px;color:#475569;">Hola <strong style="color:#001A4B;">{{user.nombre}}</strong>, así te fue en este partido:</p></td></tr><tr><td style="padding:8px 32px 8px;"><table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #E2E8F0;border-radius:8px;overflow:hidden;"><tr><td width="50%" style="padding:16px;text-align:center;border-right:1px solid #E2E8F0;"><p style="margin:0;font-size:11px;color:#64748B;text-transform:uppercase;letter-spacing:0.5px;">TU PRONÓSTICO</p><p style="margin:8px 0 0;font-size:32px;font-weight:900;color:#001A4B;font-family:'Arial Black',Arial,sans-serif;">{{business_context.goles_local}}-{{business_context.goles_visitante}}</p></td><td width="50%" style="padding:16px;text-align:center;"><p style="margin:0;font-size:11px;color:#64748B;text-transform:uppercase;letter-spacing:0.5px;">RESULTADO REAL</p><p style="margin:8px 0 0;font-size:32px;font-weight:900;color:#001A4B;font-family:'Arial Black',Arial,sans-serif;">{{business_context.resultado_local}}-{{business_context.resultado_visitante}}</p></td></tr></table></td></tr><tr><td style="padding:16px 32px 8px;text-align:center;"><div style="display:inline-block;background:#F47C00;color:#ffffff;padding:12px 28px;border-radius:50px;font-weight:900;font-size:20px;font-family:'Arial Black',Arial,sans-serif;">+{{business_context.puntos_obtenidos}} pts{{#if business_context.outcome}} — {{business_context.outcome}}{{/if}}</div></td></tr><tr><td style="padding:8px 32px 8px;text-align:center;"><p style="margin:0;font-size:15px;color:#475569;">Tu posición en el ranking: <strong style="color:#001A4B;font-size:18px;">#{{business_context.ranking_position}}</strong></p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="https://prodecaballito.com/ranking" style="display:inline-block;background:#F47C00;color:#ffffff;font-family:'Arial Black',Arial,sans-serif;font-weight:900;font-size:16px;padding:16px 36px;border-radius:50px;text-decoration:none;">Ver ranking →</a></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_3$,
    "updatedAt" = now()
  WHERE name = 'email_result_individual' AND "tenantId" = v_tenant_id;

  -- email_result_broadcast
  UPDATE templates SET
    subject = $subj_4$Resultados de la fecha — {{user.planilla_nombre}}$subj_4$,
    body = $body_4$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr><tr><td style="padding:28px 32px 8px;text-align:center;"><p style="margin:0;font-size:28px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#001A4B;">⚽ RESULTADOS</p></td></tr><tr><td style="padding:8px 32px 8px;"><p style="margin:0;font-size:15px;color:#475569;">Hola <strong style="color:#001A4B;">{{user.nombre}}</strong>, ya están los resultados de la fecha en <strong>{{user.planilla_nombre}}</strong>. Entrá a ver tu posición.</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="https://prodecaballito.com/ranking" style="display:inline-block;background:#F47C00;color:#ffffff;font-family:'Arial Black',Arial,sans-serif;font-weight:900;font-size:16px;padding:16px 36px;border-radius:50px;text-decoration:none;">Ver mi posición →</a></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_4$,
    "updatedAt" = now()
  WHERE name = 'email_result_broadcast' AND "tenantId" = v_tenant_id;

  -- email_payment_pending
  UPDATE templates SET
    subject = $subj_5$⚠️ Pago pendiente en ProdeCaballito$subj_5$,
    body = $body_5$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr><tr><td style="background:#FEF2F2;padding:20px 32px;text-align:center;border-bottom:1px solid #FECACA;"><p style="margin:0;font-size:20px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#DC2626;">⚠️ PAGO PENDIENTE</p></td></tr><tr><td style="padding:24px 32px 8px;"><p style="margin:0;font-size:15px;color:#1E293B;">Hola <strong>{{user.nombre}}</strong>, tenés un pago pendiente para continuar participando en <strong>{{user.planilla_nombre}}</strong>.</p><p style="margin:12px 0 0;font-size:15px;color:#475569;">Regularizá tu situación para no perder tu posición.</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="https://prodecaballito.com" style="display:inline-block;background:#F47C00;color:#ffffff;font-family:'Arial Black',Arial,sans-serif;font-weight:900;font-size:16px;padding:16px 36px;border-radius:50px;text-decoration:none;">Regularizar pago →</a></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_5$,
    "updatedAt" = now()
  WHERE name = 'email_payment_pending' AND "tenantId" = v_tenant_id;

  -- email_winner_personal
  UPDATE templates SET
    subject = $subj_6$🏆 ¡{{user.nombre}}, ganaste {{business_context.matchday_name}}!$subj_6$,
    body = $body_6$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr>{{#if business_context.image_url}}<tr><td style="padding:0;"><img src="{{business_context.image_url}}" alt="¡Ganaste!" width="600" style="width:100%;max-width:600px;display:block;"></td></tr>{{/if}}<tr><td style="background:#001A4B;padding:28px 32px;text-align:center;"><p style="margin:0;font-size:14px;color:#93C5FD;text-transform:uppercase;letter-spacing:1px;">{{business_context.matchday_name}}</p><p style="margin:8px 0;font-size:42px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#F47C00;letter-spacing:-1px;line-height:1.1;">¡GANASTE!</p><p style="margin:0;font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;">CON {{business_context.points}} PUNTOS</p></td></tr><tr><td style="padding:24px 32px 8px;text-align:center;"><p style="margin:0;font-size:16px;color:#1E293B;line-height:1.6;font-style:italic;">{{business_context.scorer_line}}</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="https://prodecaballito.com/ganadas" style="display:inline-block;background:#F47C00;color:#ffffff;font-family:'Arial Black',Arial,sans-serif;font-weight:900;font-size:16px;padding:16px 36px;border-radius:50px;text-decoration:none;">Ver mi historial de victorias →</a></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_6$,
    "updatedAt" = now()
  WHERE name = 'email_winner_personal' AND "tenantId" = v_tenant_id;

  -- email_winner_broadcast
  UPDATE templates SET
    subject = $subj_7$🏆 {{business_context.winner_name}} ganó {{business_context.matchday_name}}$subj_7$,
    body = $body_7$<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:0;background:#F8FAFC;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#F8FAFC;"><tr><td align="center" style="padding:24px 16px;"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #E2E8F0;"><tr><td style="background:#001A4B;padding:20px 32px;text-align:center;"><span style="font-size:22px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#ffffff;letter-spacing:-0.5px;">⚽ PRODE Caballito</span></td></tr><tr><td style="background:#001A4B;padding:28px 32px;text-align:center;"><p style="margin:0;font-size:13px;color:#93C5FD;text-transform:uppercase;letter-spacing:1px;">CRACK DE LA FECHA</p><p style="margin:8px 0;font-size:36px;font-family:'Arial Black',Arial,sans-serif;font-weight:900;color:#F47C00;letter-spacing:-0.5px;">{{business_context.winner_name}}</p><p style="margin:0;font-size:18px;color:#ffffff;font-weight:700;">{{business_context.points}} puntos · {{business_context.matchday_name}}</p></td></tr><tr><td style="padding:24px 32px 8px;"><p style="margin:0;font-size:15px;color:#475569;">Hola <strong style="color:#001A4B;">{{user.nombre}}</strong>, {{business_context.scorer_line}}</p></td></tr><tr><td style="padding:8px 32px 32px;text-align:center;"><a href="https://prodecaballito.com/ranking" style="display:inline-block;background:#F47C00;color:#ffffff;font-family:'Arial Black',Arial,sans-serif;font-weight:900;font-size:16px;padding:16px 36px;border-radius:50px;text-decoration:none;">Ver ranking →</a></td></tr><tr><td style="background:#F8FAFC;padding:20px 32px;text-align:center;border-top:1px solid #E2E8F0;"><p style="margin:0;font-size:13px;color:#94A3B8;">Con cariño, el equipo de PRODE Caballito ❤️ | <a href="https://prodecaballito.com" style="color:#F47C00;text-decoration:none;">prodecaballito.com</a></p></td></tr></table></td></tr></table></body></html>$body_7$,
    "updatedAt" = now()
  WHERE name = 'email_winner_broadcast' AND "tenantId" = v_tenant_id;

  -- email_matchday_summary
  UPDATE templates SET
    subject = $subj_8$Resumen de fecha — {{business_context.matchday_name}}$subj_8$,
